import{_ as t,o as a,c as i,a2 as e}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"Anti Yo-Yo 系统","description":"","frontmatter":{},"headers":[],"relativePath":"zh/advanced/anti-yoyo.md","filePath":"zh/advanced/anti-yoyo.md"}'),l={name:"zh/advanced/anti-yoyo.md"};function s(n,o,c,r,p,d){return a(),i("div",null,[...o[0]||(o[0]=[e('<h1 id="anti-yo-yo-系统" tabindex="-1"><i class="ph ph-arrows-clockwise"></i> Anti Yo-Yo 系统 <a class="header-anchor" href="#anti-yo-yo-系统" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-arrows-clockwise&quot;&gt;&lt;/i&gt; Anti Yo-Yo 系统&quot;">​</a></h1><p>动态缩放系统最令人恼火的问题之一是<strong>溜溜球效应 (Yo-Yo Effect)</strong>（或质量乒乓）。</p><h2 id="核心问题" tabindex="-1"><i class="ph ph-warning-circle"></i> 核心问题 <a class="header-anchor" href="#核心问题" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-warning-circle&quot;&gt;&lt;/i&gt; 核心问题&quot;">​</a></h2><p>如果没有智能控制，系统将进入无限循环：</p><ol><li>由于场景繁重，FPS 下降。</li><li>插件降低图形质量（例如，降低分辨率）。</li><li>负载下降，FPS 升至基线以上。</li><li>插件推断有可用的性能余量 (Performance Headroom)，并将图形质量恢复到最大。</li><li>FPS 再次下降。循环重复。</li></ol><p>因此，玩家会经历持续的质量闪烁 (Quality flickering)：阴影不断闪烁，图像每秒从模糊“跳”到清晰。</p><h2 id="webap-解决方案-惩罚锁定" tabindex="-1"><i class="ph ph-shield-check"></i> WebAP 解决方案：惩罚锁定 <a class="header-anchor" href="#webap-解决方案-惩罚锁定" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-shield-check&quot;&gt;&lt;/i&gt; WebAP 解决方案：惩罚锁定&quot;">​</a></h2><p>我们通过实施惩罚锁定 (Penalty Lockout) 的概念彻底根除了这个问题。它基于插件设置中的两个参数。</p><p>当插件<em>提高</em>图形质量时，它会触发一个隐藏的计时器——<strong>Detection Window</strong>（例如，15 秒）。在此时间范围内，索引器 (Indexer) 会密切监视帧稳定性。</p><p>如果 FPS 在此窗口期间突然下降，系统会得出一个明确的结论：<em>«之前的图形升级是一个错误；设备无法长距离维持此级别。»</em></p><p><strong>执行惩罚：</strong></p><ol><li>插件立即将质量降回。</li><li>应用严格的 <strong>Penalty Lockout Duration</strong>（例如，60 秒）。</li><li>在这一分钟内，<strong>严禁</strong>插件尝试再次提高图形质量，即使 FPS 飙升且处理器处于空闲状态。</li></ol><div class="tip custom-block"><p class="custom-block-title">扩展锁定 (Session Lock)</p><p>如果您的游戏动态具有以波浪形式发生的负载峰值，并且您希望在第一次下降后质量永远不要尝试恢复，只需在 <strong>Penalty Lockout Duration</strong> 字段中指定一个大数值（例如，<code>600</code> 代表 10 分钟或 <code>3600</code> 代表一小时）。这实际上将图形锁定在一致的低水平，直到游戏会话结束。</p></div><div class="info custom-block"><p class="custom-block-title">流畅度优先级</p><p>惩罚专门阻止改善渲染的尝试。如果玩家进入甚至更重的场景并且 FPS 降至临界阈值以下，插件仍可紧急进一步降低质量。系统始终将游戏流畅度置于视觉效果之上。</p></div>',14)])])}const g=t(l,[["render",s]]);export{u as __pageData,g as default};
